# Core abstractions: interfaces and classes

from utils_types import Status, Point2D

interface ISizable:
    def get_size(self) -> float: ...

@abstract
class Shape:
    name: str
    status: Status

    def __init__(self, name: str):
        self.name = name
        self.status = Status.PENDING

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape({self.name})"

class Rectangle(Shape, ISizable):
    width: float
    height: float
    corner: Point2D

    def __init__(self, width: float, height: float, corner: Point2D):
        super().__init__("Rectangle")
        self.width = width
        self.height = height
        self.corner = corner
        self.status = Status.ACTIVE

    @override
    def area(self) -> float:
        return self.width * self.height

    def get_size(self) -> float:
        return self.area()
